SELECT id,subject_code subjectCode,budget_amount budgetAmount,actual_amount actualAmount,budget_year budgetYear,in_out_type inOutType,update_time updateTime
FROM tb_budget_total

    subject_code=#{query.subjectCode}
    budget_year=#{query.budgetYear}
    in_out_type=#{query.inOutType}

ORDER BY budget_year DESC,subject_code
LIMIT #{offset},#{pageSize}

SELECT COUNT(1) FROM tb_budget_total

    subject_code=#{query.subjectCode}
    budget_year=#{query.budgetYear}
    in_out_type=#{query.inOutType}
